import express from "express";
import { CategoriesController } from "./categories.controller";
import { authGuard } from "../../middleware/authGuard";
const router = express.Router();
const categoriesController = new CategoriesController();
router.get("/all", authGuard(), categoriesController.getAllCategories.bind(categoriesController));
router.get("/:id", authGuard(), categoriesController.getSingleCategory.bind(categoriesController));
router.post("/", authGuard("provider", "admin"), categoriesController.createCategory.bind(categoriesController));
router.patch("/:id", authGuard("provider", "admin"), categoriesController.updateCategory.bind(categoriesController));
router.delete("/:id", authGuard("provider", "admin"), categoriesController.deleteCategory.bind(categoriesController));
export default router;
